type Client struct {
	ID        string
	Name      string
	Conn      net.Conn
	Addr      string
	Roles     map[Role]bool
	CreatedAt time.Time

	mu     sync.Mutex
	closed bool
}

func (c *Client) HasRole(r Role) bool {
	if c == nil || c.Roles == nil {
		return false
	}
	return c.Roles[r]
}

func (c *Client) Send(msg string) {
	c.mu.Lock()
	defer c.mu.Unlock()
	if c.closed {
		return
	}
	_, _ = c.Conn.Write([]byte(msg + "\n"))
}

func (c *Client) Close() {
	c.mu.Lock()
	if c.closed {
		c.mu.Unlock()
		return
	}
	c.closed = true
	c.mu.Unlock()
	_ = c.Conn.Close()
}

