func banUntilString(until time.Time) string {
	if until.IsZero() {
		return "perm"
	}
	return "until " + until.Format(time.RFC3339)
}

func (s *Server) Start(ctx context.Context) error {
	ln, err := net.Listen("tcp", s.addr)
	if err != nil {
		return err
	}
	s.logger.Printf("listening on %s", s.addr)

	go func() {
		<-ctx.Done()
		_ = ln.Close()
	}()

	for {
		conn, err := ln.Accept()
		if err != nil {
			select {
			case <-ctx.Done():
				return nil
			default:
			}
			s.logger.Printf("accept error: %v", err)
			continue
		}
		go s.handleConn(ctx, conn)
	}
}

func (s *Server) handleConn(ctx context.Context, conn net.Conn) {
	_ = conn.SetReadDeadline(time.Now().Add(15 * time.Second))
	br := bufio.NewReader(conn)

	helloLine, err := br.ReadString('\n')
	if err != nil {
		_ = conn.Close()
		return
	}
	helloLine = strings.TrimSpace(helloLine)

	var hello Hello
	if err := json.Unmarshal([]byte(helloLine), &hello); err != nil {
		_, _ = conn.Write([]byte("system: invalid hello\n"))
		_ = conn.Close()
		return
	}

	roles := parseRolesFromHeaders(hello.Headers)
	name := sanitizeName(hello.Name)
	if name == "" {
		name = "player"
	}
	addr := conn.RemoteAddr().String()
	ip := remoteIP(addr)

	if s.isBanned(name, ip) {
		_, _ = conn.Write([]byte("system: banned\n"))
		_ = conn.Close()
		return
	}

	id := newID()
	client := &Client{
		ID:        id,
		Name:      uniqueName(s, name),
		Conn:      conn,
		Addr:      ip,
		Roles:     roles,
		CreatedAt: time.Now(),
	}

	s.AddClient(client)
	_ = conn.SetReadDeadline(time.Time{})

	client.Send("system: welcome " + client.Name)
	s.BroadcastExcept(client.ID, "system: "+client.Name+" joined")

	s.readLoop(ctx, client, br)
}

func (s *Server) readLoop(ctx context.Context, c *Client, br *bufio.Reader) {
	defer func() {
		s.RemoveClient(c.ID)
		c.Close()
		s.Broadcast("system: " + c.Name + " left")
	}()

	for {
		select {
		case <-ctx.Done():
			return
		default:
		}
		line, err := br.ReadString('\n')
		if err != nil {
			return
		}
		line = strings.TrimRight(line, "\r\n")
		if line == "" {
			continue
		}
		if strings.HasPrefix(line, "/") {
			s.handleCommand(ctx, c, line)
		} else {
			s.Broadcast(fmt.Sprintf("chat: %s: %s", c.Name, line))
		}
	}
}

func (s *Server) handleCommand(ctx context.Context, c *Client, raw string) {
	name, args := parseCommand(raw)
	if name == "" {
		return
	}
	err := s.cmds.Execute(ctx, c, name, args)
	if err == nil {
		return
	}
	switch err {
	case ErrUnauthorized:
		c.Send("system: unauthorized")
	case ErrBadRequest:
		cmd := s.cmds.Get(name)
		if cmd != nil {
			c.Send("system: bad request. usage: " + cmd.Usage)
		} else {
			c.Send("system: bad request")
		}
	default:
		c.Send("system: error: " + err.Error())
	}
}

func (s *Server) AddClient(c *Client) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.clients[c.ID] = c
}

func (s *Server) RemoveClient(id string) {
	s.mu.Lock()
	defer s.mu.Unlock()
	delete(s.clients, id)
}

func (s *Server) Broadcast(msg string) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	for _, c := range s.clients {
		c.Send(msg)
	}
}

func (s *Server) BroadcastExcept(exceptID, msg string) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	for _, c := range s.clients {
		if c.ID == exceptID {
			continue
		}
		c.Send(msg)
	}
}

func (s *Server) findClientByName(name string) *Client {
	n := strings.ToLower(strings.TrimSpace(name))
	s.mu.RLock()
	defer s.mu.RUnlock()
	for _, c := range s.clients {
		if strings.ToLower(c.Name) == n {
			return c
		}
	}
	return nil
}

func (s *Server) kickByIP(ip, reason string) {
	ip = strings.TrimSpace(strings.ToLower(ip))
	if ip == "" {
		return
	}
	var toKick []*Client
	s.mu.RLock()
	for _, c := range s.clients {
		if strings.ToLower(c.Addr) == ip {
			toKick = append(toKick, c)
		}
	}
	s.mu.RUnlock()

	for _, c := range toKick {
		c.Send("system: " + reason)
		s.RemoveClient(c.ID)
		c.Close()
	}
}

func (s *Server) isBanned(name, ip string) bool {
	now := time.Now()
	keys := []string{strings.ToLower(strings.TrimSpace(name)), strings.ToLower(strings.TrimSpace(ip))}
	s.mu.Lock()
	defer s.mu.Unlock()

	for _, k := range keys {
		if k == "" {
			continue
		}
		until, ok := s.bans[k]
		if !ok {
			continue
		}
		if until.IsZero() {
			return true
		}
		if now.Before(until) {
			return true
		}
		delete(s.bans, k)
	}
	return false
}

type Command struct {
	Name        string
	MinRole     Role
	Usage       string
	Description string
	Handler     func(ctx context.Context, invoker *Client, args []string) error
}

type CommandRegistry struct {
	srv  *Server
	mu   sync.RWMutex
	cmds map[string]Command
}

func NewCommandRegistry(s *Server) *CommandRegistry {
	return &CommandRegistry{
		srv:  s,
		cmds: make(map[string]Command),
	}
}

func (r *CommandRegistry) Register(cmd Command) {
	r.mu.Lock()
	defer r.mu.Unlock()
	r.cmds[strings.ToLower(cmd.Name)] = cmd
}

func (r *CommandRegistry) Get(name string) *Command {
	r.mu.RLock()
	defer r.mu.RUnlock()
	cmd, ok := r.cmds[strings.ToLower(name)]
	if !ok {
		return nil
	}
	c := cmd
	return &c
}

func (r *CommandRegistry) CanRun(c *Client, cmd *Command) bool {
	if cmd == nil {
		return false
	}
	switch cmd.MinRole {
	case RolePlayer:
		return true
	case RoleMod:
		return c.HasRole(RoleMod) || c.HasRole(RoleAdmin)
	case RoleAdmin:
		return c.HasRole(RoleAdmin)
	default:
		return false
	}
}

func (r *CommandRegistry) Execute(ctx context.Context, invoker *Client, name string, args []string) error {
	cmd := r.Get(name)
	if cmd == nil {
		invoker.Send("system: unknown command")
		return nil
	}
	if !r.CanRun(invoker, cmd) {
		return ErrUnauthorized
	}
	if cmd.Handler == nil {
		return errors.New("no handler")
	}
	return cmd.Handler(ctx, invoker, args)
}

func (r *CommandRegistry) ListFor(c *Client) string {
	r.mu.RLock()
	defer r.mu.RUnlock()
	var names []string
	for _, cmd := range r.cmds {
		cc := cmd
		if r.CanRun(c, &cc) {
			names = append(names, "/"+cmd.Name)
		}
	}
	// stable-ish ordering
	sortStrings(names)
	return strings.Join(names, " ")
}

func sortStrings(a []string) {
	for i := 0; i < len(a); i++ {
		for j := i + 1; j < len(a); j++ {
			if a[j] < a[i] {
				a[i], a[j] = a[j], a[i]
			}
		}
	}
}

type Hello struct {
	Name    string            `json:"name"`
	Headers map[string]string `json:"headers"`
}

func parseRolesFromHeaders(h map[string]string) map[Role]bool {
	roles := map[Role]bool{
		RolePlayer: true,
	}
	if h == nil {
		return roles
	}

	raw := ""
	for k, v := range h {
		if strings.EqualFold(k, "X-Game-Roles") || strings.EqualFold(k, "X-Roles") || strings.EqualFold(k, "Roles") {
			raw = v
			break
		}
	}
	if raw == "" {
		return roles
	}
	for _, part := range strings.Split(raw, ",") {
		p := strings.ToLower(strings.TrimSpace(part))
		switch p {
		case "admin":
			roles[RoleAdmin] = true
		case "mod", "moderator":
			roles[RoleMod] = true
		case "player":
			roles[RolePlayer] = true
		}
	}
	if roles[RoleAdmin] {
		roles[RoleMod] = true
	}
	return roles
}

var cmdRe = regexp.MustCompile(`^/([a-zA-Z0-9_]+)(?:\s+(.*))?$`)

func parseCommand(raw string) (string, []string) {
	raw = strings.TrimSpace(raw)
	m := cmdRe.FindStringSubmatch(raw)
	if len(m) == 0 {
		return "", nil
	}
	name := strings.ToLower(m[1])
	rest := ""
	if len(m) > 2 {
		rest = strings.TrimSpace(m[2])
	}
	if rest == "" {
		return name, nil
	}
	args := splitArgs(rest)
	return name, args
}

func splitArgs(s string) []string {
	var args []string
	var cur strings.Builder
	inQuotes := false
	esc := false

	flush := func() {
		if cur.Len() > 0 {
			args = append(args, cur.String())
			cur.Reset()
		}
	}

	for _, r := range s {
		if esc {
			cur.WriteRune(r)
			esc = false
			continue
		}
		switch r {
		case '\\':
			esc = true
		case '"':
			inQuotes = !inQuotes
		case ' ', '\t':
			if inQuotes {
				cur.WriteRune(r)
			} else {
				flush()
			}
		default:
			cur.WriteRune(r)
		}
	}
	flush()
	return args
}

func sanitizeName(n string) string {
	n = strings.TrimSpace(n)
	if n == "" {
		return ""
	}
	n = strings.Map(func(r rune) rune {
		switch {
		case r >= 'a' && r <= 'z':
			return r
		case r >= 'A' && r <= 'Z':
			return r
		case r >= '0' && r <= '9':
			return r
		case r == '_' || r == '-' || r == '.':
			return r
		default:
			return -1
		}
	}, n)
	if len(n) > 24 {
		n = n[:24]
	}
	return n
}

func uniqueName(s *Server, base string) string {
	base = sanitizeName(base)
	if base == "" {
		base = "player"
	}
	name := base
	i := 1
	for {
		if s.findClientByName(name) == nil && !s.isBanned(name, "") {
			return name
		}
		i++
		name = fmt.Sprintf("%s%d", base, i)
		if i > 9999 {
			return fmt.Sprintf("%s_%s", base, newID()[:6])
		}
	}
}

func newID() string {
	var b [16]byte
	_, _ = rand.Read(b[:])
	return hex.EncodeToString(b[:])
}

func remoteIP(addr string) string {
	// addr typically "ip:port" for TCP
	host, _, err := net.SplitHostPort(addr)
	if err == nil {
		return host
	}
	return addr
}

func main() {
	addr := ":7777"
	if v := os.Getenv("GAME_SERVER_ADDR"); v != "" {
		addr = v
	}

	srv := NewServer(addr)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	go func() {
		ch := make(chan os.Signal, 2)
		signal.Notify(ch, syscall.SIGINT, syscall.SIGTERM)
		<-ch
		cancel()
	}()

	if err := srv.Start(ctx); err != nil {
		log.Fatal(err)
	}
}

